
// ══════════════════════════════════════════════════════════
// 阶段主题：随堕落阶段推移，界面从暗金走向艳紫
// 只定义 5 个变量，其余全部派生——克制是层次的前提
// ══════════════════════════════════════════════════════════
.th-stage-1 {
  --acc: #d2b273; // 暗金 · 保守居家
  --acc2: #9a7f42;
  --bg: #131009;
  --panel: rgba(255, 252, 240, 0.035);
  --line: rgba(210, 178, 115, 0.16);
}
.th-stage-2 {
  --acc: #c39be0; // 动摇紫
  --acc2: #8f6ab0;
  --bg: #120d18;
  --panel: rgba(246, 240, 255, 0.04);
  --line: rgba(195, 155, 224, 0.16);
}
.th-stage-3 {
  --acc: #ea8fb4; // 沉溺粉
  --acc2: #b45f84;
  --bg: #170d13;
  --panel: rgba(255, 240, 248, 0.04);
  --line: rgba(234, 143, 180, 0.18);
}
.th-stage-4 {
  --acc: #f0559f; // 疯狂品红
  --acc2: #b32e73;
  --bg: #1a0a14;
  --panel: rgba(255, 235, 246, 0.05);
  --line: rgba(240, 85, 159, 0.2);
}
.th-stage-5 {
  --acc: #cf7bf5; // 圆满电紫
  --acc2: #9747c9;
  --bg: #140a1d;
  --panel: rgba(248, 238, 255, 0.05);
  --line: rgba(207, 123, 245, 0.2);
}

// 阶段无关的功能色
$vuln: #ff6b9d; // 心防松动 · 唯一允许高调发光的颜色
$safe: #79c48a;
$warn: #e8a94f;
$danger: #e06868;
$info: #6fb9dc;

$serif: 'Noto Serif SC', 'Songti SC', 'STSong', serif;

// ══════════════════════════════════════════════════════════
// 根容器
// ══════════════════════════════════════════════════════════
.ql-root {
  width: 100%;
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid var(--line);
  background:
    radial-gradient(130% 80% at 88% -12%, color-mix(in srgb, var(--acc) 9%, transparent), transparent 55%),
    radial-gradient(100% 60% at 0% 105%, color-mix(in srgb, var(--acc2) 7%, transparent), transparent 50%),
    var(--bg);
  color: #d9d2c7;
  font-family: -apple-system, 'PingFang SC', 'HarmonyOS Sans SC', 'Source Han Sans SC', 'Microsoft YaHei', sans-serif;
  font-size: 13px;
  line-height: 1.6;
  transition: border-color 0.5s;
}

.panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 12px 14px 16px;
}

// ══════════════════════════════════════════════════════════
// 顶栏
// ══════════════════════════════════════════════════════════
.topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding-bottom: 10px;
  border-bottom: 1px solid var(--line);
}
.world {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 11.5px;
  color: color-mix(in srgb, var(--acc) 55%, #999);
  letter-spacing: 0.4px;
  min-width: 0;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.sep {
  width: 3px;
  height: 3px;
  border-radius: 50%;
  background: color-mix(in srgb, var(--acc) 45%, transparent);
  flex: none;
}
.coin {
  flex: none;
  font-size: 12px;
  font-weight: 600;
  color: var(--acc);
  letter-spacing: 0.5px;
  padding: 2px 10px;
  border-radius: 20px;
  background: var(--panel);
  border: 1px solid var(--line);
}

// ══════════════════════════════════════════════════════════
// 角色切换
// ══════════════════════════════════════════════════════════
.tabs {
  display: flex;
  gap: 8px;
}
.tab {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 7px;
  padding: 9px 8px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: var(--panel);
  color: inherit;
  font-family: inherit;
  cursor: pointer;
  transition: border-color 0.25s, background 0.25s;

  &:hover {
    border-color: color-mix(in srgb, var(--acc) 40%, transparent);
  }
  &.active {
    border-color: color-mix(in srgb, var(--acc) 55%, transparent);
    background: linear-gradient(150deg, color-mix(in srgb, var(--acc) 13%, transparent), transparent 70%);

    .nm {
      color: var(--acc);
    }
  }
}
.presence {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.16);
  flex: none;
  transition: background 0.3s, box-shadow 0.3s;

  &.on {
    background: $safe;
    box-shadow: 0 0 6px rgba(121, 196, 138, 0.7);
  }
}
.nm {
  font-size: 15px;
  font-weight: 700;
  letter-spacing: 1px;
  color: #cfc6b8;
  transition: color 0.25s;
}
.rl {
  font-size: 10.5px;
  color: color-mix(in srgb, var(--acc) 42%, #888);
  letter-spacing: 1px;
}

// ══════════════════════════════════════════════════════════
// 阶段 · 情绪 · 三维
// ══════════════════════════════════════════════════════════
.hero {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 12px 13px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: var(--panel);
}
.hero-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}
.stage {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}
.stage-no {
  flex: none;
  width: 38px;
  height: 38px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  border: 1.5px solid color-mix(in srgb, var(--acc) 60%, transparent);
  color: var(--acc);
  font-size: 18px;
  font-weight: 800;
  font-family: $serif;
  background: radial-gradient(circle, color-mix(in srgb, var(--acc) 10%, transparent), transparent 70%);
}
.stage-meta {
  display: flex;
  flex-direction: column;
  min-width: 0;

  .stage-title {
    font-family: $serif;
    font-size: 16px;
    font-weight: 700;
    color: var(--acc);
    letter-spacing: 3px;
    line-height: 1.3;
  }
  small {
    font-size: 10.5px;
    color: color-mix(in srgb, var(--acc) 42%, #888);
    letter-spacing: 0.6px;
  }
}
.emotion {
  flex: none;
  font-size: 12px;
  color: #cfc6b8;
  padding: 3px 12px;
  border-radius: 20px;
  border: 1px solid var(--line);
  background: rgba(0, 0, 0, 0.25);
  letter-spacing: 1px;

  &.vuln {
    color: $vuln;
    border-color: rgba(255, 107, 157, 0.5);
    font-weight: 700;
    animation: vuln-pulse 1.6s ease-in-out infinite;
  }
}
@keyframes vuln-pulse {
  0%,
  100% {
    box-shadow: 0 0 4px rgba(255, 107, 157, 0.25);
  }
  50% {
    box-shadow: 0 0 14px rgba(255, 107, 157, 0.6);
  }
}

// 三维数值：一行一条，紧凑
.bars {
  display: flex;
  flex-direction: column;
  gap: 7px;
}
.bar {
  display: flex;
  align-items: center;
  gap: 9px;
  font-size: 11.5px;
}
.bl {
  flex: none;
  width: 34px;
  color: color-mix(in srgb, var(--acc) 48%, #999);
  letter-spacing: 1px;
}
.track {
  flex: 1;
  height: 5px;
  border-radius: 3px;
  background: rgba(0, 0, 0, 0.45);
  overflow: hidden;
}
.fill {
  display: block;
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}
.f-corrupt {
  background: linear-gradient(90deg, var(--acc2), var(--acc));
}
.f-user {
  background: linear-gradient(90deg, #b3577e, #e58bab);
}
.f-suwen {
  background: linear-gradient(90deg, #4e5560, #8a93a1);
}
.f-grow {
  background: linear-gradient(90deg, var(--acc2), var(--acc));
}
.f-warn {
  background: linear-gradient(90deg, #c98f3d, $warn);
}
.f-danger {
  background: linear-gradient(90deg, #b34848, $danger);
}
.bv {
  flex: none;
  min-width: 24px;
  text-align: right;
  font-weight: 700;
  font-size: 12px;
  color: #cfc6b8;
  font-variant-numeric: tabular-nums;
}

// 心防松动横幅：全界面唯一的高调元素
.vuln-banner {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 7px 11px;
  border-radius: 8px;
  border: 1px solid rgba(255, 107, 157, 0.45);
  background: linear-gradient(90deg, rgba(255, 107, 157, 0.14), rgba(255, 107, 157, 0.03));
  color: $vuln;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 1px;
  animation: vuln-pulse 1.6s ease-in-out infinite;

  i {
    font-style: normal;
    animation: vuln-sway 0.7s ease-in-out infinite alternate;
  }
}
@keyframes vuln-sway {
  from {
    transform: rotate(-8deg);
  }
  to {
    transform: rotate(8deg);
  }
}

// 内心独白：衬线引文，"她的声音"
.inner-voice {
  margin: 0;
  padding: 8px 12px;
  border-left: 2px solid color-mix(in srgb, var(--acc) 50%, transparent);
  border-radius: 0 6px 6px 0;
  background: rgba(0, 0, 0, 0.22);
  font-family: $serif;
  font-size: 12.5px;
  font-style: italic;
  color: #c4bbae;
  letter-spacing: 0.3px;
}
.aura {
  font-size: 11px;
  font-style: italic;
  color: color-mix(in srgb, var(--acc) 45%, #888);
  text-align: right;
  letter-spacing: 0.5px;
}

// ══════════════════════════════════════════════════════════
// 念头植入
// ══════════════════════════════════════════════════════════
.implant {
  display: flex;
  flex-direction: column;
  gap: 9px;
  padding: 11px 13px;
  border: 1px solid color-mix(in srgb, var(--acc) 26%, transparent);
  border-radius: 10px;
  background: linear-gradient(160deg, color-mix(in srgb, var(--acc) 6%, transparent), transparent 60%);
}
.implant-head {
  display: flex;
  align-items: center;
  gap: 8px;
}
.ttl {
  font-family: $serif;
  font-size: 13.5px;
  font-weight: 700;
  color: var(--acc);
  letter-spacing: 2px;
}
.target {
  font-size: 11.5px;
  color: color-mix(in srgb, var(--acc) 55%, #999);
  letter-spacing: 0.5px;
}
.quota {
  display: inline-flex;
  gap: 4px;
  margin-left: auto;

  i {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.14);
    transition: background 0.3s;

    &.used {
      background: var(--acc);
      box-shadow: 0 0 5px color-mix(in srgb, var(--acc) 60%, transparent);
    }
  }
}
.implant-row {
  display: flex;
  align-items: center;
  gap: 8px;

  input {
    flex: 1;
    min-width: 0;
    padding: 8px 12px;
    border: 1px solid var(--line);
    border-radius: 8px;
    background: rgba(0, 0, 0, 0.35);
    color: #e2dbcf;
    font-size: 13px;
    font-family: inherit;
    letter-spacing: 0.5px;
    transition: border-color 0.2s;

    &:focus {
      outline: none;
      border-color: color-mix(in srgb, var(--acc) 65%, transparent);
    }
    &::placeholder {
      color: color-mix(in srgb, var(--acc) 30%, #666);
    }
  }
}
.count {
  flex: none;
  font-size: 10px;
  color: #666;
  font-variant-numeric: tabular-nums;

  &.max {
    color: $danger;
    font-weight: 700;
  }
}
.go {
  flex: none;
  padding: 8px 18px;
  border: none;
  border-radius: 8px;
  background: linear-gradient(135deg, var(--acc2), var(--acc));
  color: #16100a;
  font-size: 13px;
  font-weight: 800;
  font-family: inherit;
  letter-spacing: 3px;
  cursor: pointer;
  transition: filter 0.2s, transform 0.15s;

  &:hover:not(:disabled) {
    filter: brightness(1.15);
    transform: translateY(-1px);
  }
  &:disabled {
    opacity: 0.3;
    cursor: not-allowed;
  }
}
.msg {
  margin: 0;
  padding: 5px 10px;
  border-radius: 6px;
  font-size: 11.5px;
  letter-spacing: 0.4px;

  &.success {
    color: $safe;
    background: rgba(121, 196, 138, 0.1);
    border-left: 2px solid $safe;
  }
  &.error {
    color: $danger;
    background: rgba(224, 104, 104, 0.1);
    border-left: 2px solid $danger;
  }
  &.warn {
    color: $warn;
    background: rgba(232, 169, 79, 0.1);
    border-left: 2px solid $warn;
  }
}

// ══════════════════════════════════════════════════════════
// 列表区布局：移动端单列，≥640px 双列
// ══════════════════════════════════════════════════════════
.grid {
  display: flex;
  flex-direction: column;
  gap: 12px;
}
.col {
  display: flex;
  flex-direction: column;
  gap: 12px;
}
@media (min-width: 640px) {
  .grid {
    display: grid;
    grid-template-columns: 1.08fr 0.92fr;
    align-items: start;
  }
}

// ══════════════════════════════════════════════════════════
// 卡片
// ══════════════════════════════════════════════════════════
.card {
  padding: 11px 13px;
  border: 1px solid var(--line);
  border-radius: 10px;
  background: var(--panel);

  h3 {
    display: flex;
    align-items: center;
    gap: 8px;
    margin: 0 0 9px;
    padding-bottom: 7px;
    border-bottom: 1px solid var(--line);
    font-family: $serif;
    font-size: 13px;
    font-weight: 700;
    color: var(--acc);
    letter-spacing: 2px;

    em {
      margin-left: auto;
      font-style: normal;
      font-size: 11px;
      font-weight: 400;
      color: color-mix(in srgb, var(--acc) 45%, #888);
      font-variant-numeric: tabular-nums;
    }
  }
}
.empty {
  margin: 0;
  padding: 8px 0;
  text-align: center;
  font-size: 11.5px;
  font-style: italic;
  color: color-mix(in srgb, var(--acc) 32%, #666);
  letter-spacing: 1px;
}
.note {
  margin: 8px 0 0;
  padding: 5px 9px;
  border-radius: 6px;
  font-size: 11px;
  letter-spacing: 0.3px;

  &.warn {
    color: $warn;
    background: rgba(232, 169, 79, 0.09);
    border-left: 2px solid $warn;
  }
  &.safe {
    color: $safe;
    background: rgba(121, 196, 138, 0.08);
    border-left: 2px solid $safe;
  }
}

// ══════════════════════════════════════════════════════════
// 念头条目
// ══════════════════════════════════════════════════════════
.thought {
  padding: 8px 10px;
  border-radius: 8px;
  background: rgba(0, 0, 0, 0.24);
  border-left: 2px solid transparent;
  transition: border-color 0.25s, background 0.25s;

  & + .thought {
    margin-top: 7px;
  }
  &:hover {
    background: rgba(0, 0, 0, 0.36);
    border-left-color: var(--acc);
  }
}
.t-head {
  display: flex;
  align-items: center;
  gap: 7px;
  flex-wrap: wrap;
  margin-bottom: 4px;
}
.state {
  font-size: 10px;
  font-weight: 600;
  padding: 1px 8px;
  border-radius: 10px;
  letter-spacing: 0.5px;

  &.growing {
    color: $safe;
    background: rgba(121, 196, 138, 0.14);
  }
  &.pending {
    color: $info;
    background: rgba(111, 185, 220, 0.14);
  }
  &.rejected {
    color: $danger;
    background: rgba(224, 104, 104, 0.14);
  }
  &.mature {
    color: var(--acc);
    background: color-mix(in srgb, var(--acc) 16%, transparent);
  }
}
.t-type {
  font-size: 10.5px;
  color: color-mix(in srgb, var(--acc) 48%, #999);
  letter-spacing: 0.5px;
}
.t-diff {
  font-size: 10px;
  color: $warn;
  padding: 0 6px;
  border-radius: 4px;
  border: 1px solid rgba(232, 169, 79, 0.35);
}
.t-body {
  font-family: $serif;
  font-size: 13px;
  color: #ddd5c8;
  letter-spacing: 0.4px;
  margin-bottom: 4px;
}
.t-prog {
  display: flex;
  align-items: center;
  gap: 8px;

  .track {
    flex: 1;
  }
  .pv {
    flex: none;
    font-size: 10px;
    color: color-mix(in srgb, var(--acc) 50%, #999);
    font-variant-numeric: tabular-nums;
  }
}
.t-reject {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  font-size: 11px;
  color: $danger;
}

// 通用幽灵按钮
.ghost {
  flex: none;
  padding: 3px 11px;
  border: 1px solid $danger;
  border-radius: 6px;
  background: transparent;
  color: $danger;
  font-size: 10.5px;
  font-family: inherit;
  letter-spacing: 0.5px;
  cursor: pointer;
  transition: background 0.2s;

  &:hover {
    background: rgba(224, 104, 104, 0.15);
  }
  &.gold {
    border-color: color-mix(in srgb, var(--acc) 60%, transparent);
    color: var(--acc);

    &:hover {
      background: color-mix(in srgb, var(--acc) 14%, transparent);
    }
  }
}

// ══════════════════════════════════════════════════════════
// 习惯
// ══════════════════════════════════════════════════════════
.habit {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 6px 10px;
  border-radius: 7px;
  background: rgba(0, 0, 0, 0.24);
  border-left: 2px solid color-mix(in srgb, var(--acc) 35%, transparent);

  & + .habit {
    margin-top: 6px;
  }
}
.h-text {
  font-family: $serif;
  font-size: 12.5px;
  color: #cfe3d0;
  letter-spacing: 0.3px;
}

// ══════════════════════════════════════════════════════════
// 苏文
// ══════════════════════════════════════════════════════════
.chip {
  margin-left: auto;
  font-size: 10.5px;
  font-weight: 600;
  padding: 1px 10px;
  border-radius: 10px;
  letter-spacing: 0.5px;

  &.home {
    color: $danger;
    background: rgba(224, 104, 104, 0.14);
  }
  &.away {
    color: $safe;
    background: rgba(121, 196, 138, 0.14);
  }
  &.sleeping {
    color: $info;
    background: rgba(111, 185, 220, 0.14);
  }
}
.s-loc {
  font-size: 12px;
  color: color-mix(in srgb, var(--acc) 55%, #999);
  margin-bottom: 8px;
  letter-spacing: 0.4px;
}

// ══════════════════════════════════════════════════════════
// 仪容
// ══════════════════════════════════════════════════════════
.tags {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 8px;
}
.tag {
  font-size: 10.5px;
  padding: 2px 10px;
  border-radius: 12px;
  color: var(--acc);
  background: color-mix(in srgb, var(--acc) 12%, transparent);
  letter-spacing: 0.5px;

  &.line {
    background: transparent;
    border: 1px solid color-mix(in srgb, var(--acc) 35%, transparent);
    color: color-mix(in srgb, var(--acc) 70%, #aaa);
  }
}
.attire {
  margin: 0;
  display: flex;
  flex-direction: column;

  > div {
    display: flex;
    gap: 10px;
    padding: 3px 0;
    font-size: 11.5px;

    & + div {
      border-top: 1px dashed color-mix(in srgb, var(--acc) 10%, transparent);
    }
  }
  dt {
    flex: none;
    width: 30px;
    color: color-mix(in srgb, var(--acc) 45%, #888);
    letter-spacing: 1px;
    font-size: 10.5px;
    line-height: inherit;
  }
  dd {
    margin: 0;
    color: #c4bbae;
  }
}

// ══════════════════════════════════════════════════════════
// 窄屏微调
// ══════════════════════════════════════════════════════════
@media (max-width: 380px) {
  .panel {
    padding: 10px 10px 14px;
  }
  .stage-title {
    letter-spacing: 2px;
  }
  .go {
    padding: 8px 14px;
    letter-spacing: 1px;
  }
}
